.darma-loader-darma-custom-603 {color: var(--loader-color, #16a34a);
  --loader-secondary-color: #86efac;
  --loader-bg: #ffffff;
   width: 30px;
   height: 60px;
   padding-top: 60px;
   box-sizing: border-box;
   display: grid;
   background: linear-gradient(currentColor 0 0) bottom/10px calc(100% - 15px), conic-gradient(from 134deg at top,#0000 ,currentColor 1deg 90deg,#0000 91deg) top/100% 15px;
   background-origin: content-box;
   background-repeat: no-repeat;
   animation: darma-loader-darma-custom-603-l10-0 2s infinite;
}
.darma-loader-darma-custom-603:before, .darma-loader-darma-custom-603:after  {
  content: "";
   grid-area: 1/1;
   background:inherit;
   background-size: 10px calc(100% - 25px),100% 25px;
   animation: darma-loader-darma-custom-603-l10-1 2s infinite;
}
.darma-loader-darma-custom-603:after  {
  background-size: 10px calc(100% - 30px),100% 30px;
   animation: darma-loader-darma-custom-603-l10-2 2s infinite;
}
@keyframes darma-loader-darma-custom-603-l10-0  {
  25%,100% {padding-top:0px}
}
@keyframes darma-loader-darma-custom-603-l10-1  {
  0%,25% {margin:60px -10px 0}
50%,100% {margin:8px -10px 0}
}
@keyframes darma-loader-darma-custom-603-l10-2  {
  0%,50% {margin:60px -15px 0}
75%,100% {margin:20px -15px 0}
}
